import time
import json
import hashlib
from functools import wraps
from typing import Callable

def tool_cache(ttl: int = 60):
    """
    Decorator that caches tool call results by (name, arguments) for `ttl` seconds.
    Use for idempotent, read-only tools. Do NOT use for write tools.
    """
    _cache: dict[str, tuple[float, str]] = {}

    def decorator(fn: Callable) -> Callable:
        @wraps(fn)
        def wrapper(name: str, arguments: dict) -> str:
            cache_key = hashlib.sha256(
                json.dumps({"name": name, "args": arguments}, sort_keys=True).encode()
            ).hexdigest()

            if cache_key in _cache:
                expires_at, result = _cache[cache_key]
                if time.time() < expires_at:
                    return result   # cache hit

            result = fn(name, arguments)
            _cache[cache_key] = (time.time() + ttl, result)
            return result

        return wrapper
    return decorator

@tool_cache(ttl=300)   # cache for 5 minutes
def call_tool(name: str, arguments: dict) -> str:
    """Your actual tool dispatch logic."""
    if name == "get_weather":
        city = arguments["city"]
        # ... real API call ...
        return json.dumps({"city": city, "temp": 22, "desc": "Sunny"})
    return json.dumps({"error": f"Unknown tool: {name}"})

# First call — hits the real API
r1 = call_tool("get_weather", {"city": "Paris"})
# Second call within 5 minutes — served from cache
r2 = call_tool("get_weather", {"city": "Paris"})
assert r1 == r2   # same result, no API call
